  return function evaluateTemplate(template: string, data: Record<string, any>): string {
    return template.replace(/\{\{(.+?)\}\}/g, (match, expression) => {
      try {
        // Create a function with data properties as variables
        const dataKeys = Object.keys(data);
        const dataValues = Object.values(data);

        // Use Function constructor to evaluate the expression safely within scope
        const evaluator = new Function(...dataKeys, `return ${expression}`);
        const result = evaluator(...dataValues);

        return String(result);
      } catch (error) {
        return `[Error: ${expression}]`;
      }
    });
  };
}

