import crypto from 'crypto';

function generateDocumentFingerprint(content: string): string {
  return crypto
    .createHash('sha256')
    .update(content)
    .digest('hex');
}

// Example usage:
const doc1 = "This is my document content";
const doc2 = "This is my document content";
const doc3 = "This is different content";

const hash1 = generateDocumentFingerprint(doc1);
const hash2 = generateDocumentFingerprint(doc2);
const hash3 = generateDocumentFingerprint(doc3);

console.log("Document 1 fingerprint:", hash1);
console.log("Document 2 fingerprint:", hash2);
console.log("Document 3 fingerprint:", hash3);

console.log("Doc1 === Doc2:", hash1 === hash2); // true
console.log("Doc1 === Doc3:", hash1 === hash3); // false
```

This function uses SHA-256 to generate a cryptographically secure fingerprint of the document content. The same content will always produce the same hash, making it ideal for change detection - if the document changes even slightly, the hash will be completely different.

